name: Deploy Preview

on:
  pull_request:
    types: [opened, synchronize, reopened]

concurrency:
  group: deploy-preview-${{ github.event.pull_request.number }}
  cancel-in-progress: true

jobs:
  deploy:
    name: Railway Preview
    runs-on: ubuntu-latest
    environment:
      name: pr-${{ github.event.pull_request.number }}
      url: ${{ steps.deploy.outputs.ui_url }}
    steps:
      - uses: actions/checkout@v4

      - name: Install Railway CLI
        run: curl -fsSL https://railway.com/install.sh | sh

      - name: Create and deploy preview environment
        id: deploy
        env:
          RAILWAY_TOKEN: ${{ secrets.RAILWAY_TOKEN }}
          RAILWAY_PROJECT_ID: ${{ secrets.RAILWAY_PROJECT_ID }}
        run: |
          ENV_NAME="pr-${{ github.event.pull_request.number }}"

          # Create environment (idempotent — ignores error if it exists)
          railway environment new "$ENV_NAME" 2>/dev/null || true

          # Deploy server (repo root as context — Dockerfile references go.work, core/, sdk/go/)
          railway up --service server --environment "$ENV_NAME" --detach --project "$RAILWAY_PROJECT_ID" .

          # Deploy UI (ui/ subdirectory as context)
          railway up --service ui --environment "$ENV_NAME" --detach --project "$RAILWAY_PROJECT_ID" ./ui

          # Capture the public UI URL
          UI_URL=$(railway domain --service ui --environment "$ENV_NAME" 2>/dev/null || echo "pending")
          echo "ui_url=$UI_URL" >> "$GITHUB_OUTPUT"

      - name: Comment PR with preview URL
        uses: actions/github-script@v7
        with:
          script: |
            const url = '${{ steps.deploy.outputs.ui_url }}';
            const body = `## Railway Preview Environment

            | Service | URL |
            |---------|-----|
            | UI | ${url} |

            _Deployed from commit ${{ github.sha }}_`;

            const comments = await github.rest.issues.listComments({
              owner: context.repo.owner,
              repo: context.repo.repo,
              issue_number: context.issue.number,
            });
            const botComment = comments.data.find(c =>
              c.body.includes('Railway Preview Environment')
            );
            if (botComment) {
              await github.rest.issues.updateComment({
                owner: context.repo.owner,
                repo: context.repo.repo,
                comment_id: botComment.id,
                body,
              });
            } else {
              await github.rest.issues.createComment({
                owner: context.repo.owner,
                repo: context.repo.repo,
                issue_number: context.issue.number,
                body,
              });
            }

